defmodule MyApp.Cache do
  use GenServer

  @typedoc "Public cache value returned to callers."
  @type value :: %{key: String.t(), value: term(), expires_at: DateTime.t()}

  @typedoc "Internal cache state. Not part of the public contract."
  @type state :: %{table: :ets.tid(), metrics: map(), last_compaction: DateTime.t()}

  def fetch(key), do: GenServer.call(__MODULE__, {:fetch, key})

  @impl true
  def init(_opts) do
    {:ok, %{table: :ets.new(:cache, [:set]), metrics: %{}, last_compaction: DateTime.utc_now()}}
  end

  @impl true
  def handle_call({:fetch, key}, _from, state) do
    # Returning the entire internal state to the caller leaks implementation details.
    {:reply, state, state}
  end
end

defmodule MyApp.Cache do
  use GenServer

  @typedoc "Public cache value returned to callers."
  @type value :: %{key: String.t(), value: term(), expires_at: DateTime.t()}

  @typedoc "Internal cache state. Not part of the public contract."
  @type state :: %{table: :ets.tid(), metrics: map(), last_compaction: DateTime.t()}

  def fetch(key), do: GenServer.call(__MODULE__, {:fetch, key})

  @impl true
  def init(_opts) do
    {:ok, %{table: :ets.new(:cache, [:set]), metrics: %{}, last_compaction: DateTime.utc_now()}}
  end

  @impl true
  def handle_call({:fetch, key}, _from, state) do
    reply =
      case :ets.lookup(state.table, key) do
        [{^key, value, expires_at}] -> {:ok, %{key: key, value: value, expires_at: expires_at}}
        [] -> {:error, :not_found}
      end

    {:reply, reply, state}
  end
end
